        super.onCreate();
        // TODO (producción): cargar estado persistido
        // SharedPreferences prefs = getSharedPreferences("funz_prefs", MODE_PRIVATE);
        // AppState s = AppState.getInstance();
        // s.setUsername(prefs.getString("username", "Usuario"));
