package mx.unam.fc.icat.funz.data;

import android.app.Application;

import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

import mx.unam.fc.icat.funz.repository.AppStateRepository;
import mx.unam.fc.icat.funz.repository.ExerciseRepository;

/**
 * FunZApp — Clase Application de FunZ.
 *<p>
 * Punto de entrada global de la app. En producción se usaría para:
 *   - Cargar AppState desde SharedPreferences al arrancar.
 *   - Guardar AppState en SharedPreferences al ir a background.
 * <p>
 * Registrada en AndroidManifest.xml con android:name=".FunZApp".
 */
public class FunZApp extends Application {

    private ExecutorService ioExecutor;
    private ExerciseRepository exerciseRepository;
    private AppStateRepository appStateRepository;

    @Override
    public void onCreate() {
        super.onCreate();
        // TODO (producción): cargar estado persistido
        // SharedPreferences prefs = getSharedPreferences("funz_prefs", MODE_PRIVATE);
        // AppState s = AppState.getInstance();
        // s.setUsername(prefs.getString("username", "Usuario"));
        // s.addPoints(prefs.getInt("points", 0));
        // Conectar AppState a SharedPreferences
        AppState.getInstance().init(this);

        // Fuente única de hilos/repositorios para toda la app.
        ioExecutor = Executors.newSingleThreadExecutor();
        exerciseRepository = new ExerciseRepository(this, ioExecutor);
        appStateRepository = new AppStateRepository(AppState.getInstance());
    }

    public ExerciseRepository getExerciseRepository() {
        return exerciseRepository;
    }

    public AppStateRepository getAppStateRepository() {
        return appStateRepository;
    }

    @Override
    public void onTerminate() {
        super.onTerminate();
        if (ioExecutor != null) {
            ioExecutor.shutdownNow();
        }
        // TODO (producción): persistir AppState
    }
}

package mx.unam.fc.icat.funz.model;

import androidx.annotation.NonNull;

import java.util.UUID;

/**
 * Termino — Entidad que representa un elemento atómico de una ecuación.
 *
 * Cada término tiene:
 *   - Un identificador único {@link #id} para rastrear el elemento durante
 *     operaciones de Drag & Drop sin depender de su posición en la lista.
 *   - Un {@link TipoTermino} que clasifica el elemento semánticamente.
 *   - Un símbolo de visualización ({@link #simbolo}) listo para mostrar en la UI.
 *   - Datos numéricos ({@link #coeficiente}, {@link #valor}) para la lógica algebraica.
 *
 * <h3>Tipos de término</h3>
 * <ul>
 *   <li>{@link TipoTermino#VARIABLE}  — p. ej. "x", "2x", "-x"</li>
 *   <li>{@link TipoTermino#CONSTANTE} — p. ej. "5", "-3", "+7"</li>
 *   <li>{@link TipoTermino#OPERADOR}  — p. ej. "+", "-", "×", "÷"</li>
 *   <li>{@link TipoTermino#IGUAL}     — el signo "="</li>
 * </ul>
 *
 * <h3>Uso con Drag & Drop</h3>
 * Al iniciar un drag, codifica el {@link #id} del término en el ClipData.
 * Al soltarlo en un destino, el ViewModel localiza el término por su id
 * con {@code ecuacion.buscarPorId(id)} e invoca la operación correspondiente.
 */
public class Termino {

    // ════════════════════════════════════════════════════════════════════════
    //  Enum de tipo de término
    // ════════════════════════════════════════════════════════════════════════

    /**
     * Clasificación semántica de un término dentro de la ecuación.
     */
    public enum TipoTermino {
        /** Incógnita algebraica; puede llevar coeficiente entero (p. ej. 2x). */
        VARIABLE,
        /** Valor numérico entero, positivo o negativo.                          */
        CONSTANTE,
        /** Operador aritmético: +, −, ×, ÷.                                    */
        OPERADOR,
        /** Signo de igualdad "=" que separa los dos lados de la ecuación.      */
        IGUAL
    }

    // ════════════════════════════════════════════════════════════════════════
    //  Campos de instancia
    // ════════════════════════════════════════════════════════════════════════

    /** Identificador único inmutable; sirve como etiqueta en Drag & Drop. */
    @NonNull
    private final String id;

    /** Clasificación semántica. */
    @NonNull
    private TipoTermino tipo;

    /**
     * Símbolo de visualización tal como debe aparecer en pantalla.
     * Ejemplos: "x", "2x", "-x", "+5", "-3", "+", "=".
     */
    @NonNull
    private String simbolo;

    /**
     * Coeficiente numérico para términos de tipo {@link TipoTermino#VARIABLE}.
     * Ejemplos: 1 para "x", 2 para "2x", -1 para "-x".
     * Para otros tipos el valor carece de significado.
     */
    private int coeficiente;

    /**
     * Valor numérico para términos de tipo {@link TipoTermino#CONSTANTE}.
     * Puede ser negativo.
     */
    private int valor;

    /**
     * Indica si el término es positivo ({@code true}) o negativo ({@code false}).
     * Aplica a VARIABLE y CONSTANTE.
     */
    private boolean positivo;

    // ════════════════════════════════════════════════════════════════════════
    //  Constructor privado — usa los métodos de fábrica
    // ════════════════════════════════════════════════════════════════════════

    private Termino(@NonNull TipoTermino tipo,
                    @NonNull String simbolo,
                    int coeficiente,
                    int valor,
                    boolean positivo) {
        this.id          = UUID.randomUUID().toString();
        this.tipo        = tipo;
        this.simbolo     = simbolo;
        this.coeficiente = coeficiente;
        this.valor       = valor;
        this.positivo    = positivo;
    }

    // ════════════════════════════════════════════════════════════════════════
    //  Métodos de fábrica (Factory Methods)
    // ════════════════════════════════════════════════════════════════════════

    /**
     * Crea una variable con coeficiente entero.
     *
     * @param coeficiente Número que multiplica a x; puede ser negativo.
     * @return Término de tipo VARIABLE.
     * <pre>
     *   crearVariable(1)  → "x"
     *   crearVariable(2)  → "2x"
     *   crearVariable(-1) → "-x"
     *   crearVariable(-3) → "-3x"
     * </pre>
     */
    public static Termino crearVariable(int coeficiente) {
        String simbolo;
        if (coeficiente == 1)       simbolo = "x";
        else if (coeficiente == -1) simbolo = "-x";
        else                        simbolo = coeficiente + "x";
        return new Termino(TipoTermino.VARIABLE, simbolo, coeficiente, 0, coeficiente >= 0);
    }

    /**
     * Crea una constante entera.
     *
     * @param valor Valor numérico (positivo o negativo).
     * @return Término de tipo CONSTANTE.
     * <pre>
     *   crearConstante(5)  → "+5"
     *   crearConstante(-3) → "-3"
     * </pre>
     */
    public static Termino crearConstante(int valor) {
        String simbolo = valor >= 0 ? "+" + valor : String.valueOf(valor);
        return new Termino(TipoTermino.CONSTANTE, simbolo, 0, valor, valor >= 0);
    }

    /**
     * Crea un operador aritmético.
     *
     * @param operador Símbolo del operador: "+", "-", "×", "÷".
     * @return Término de tipo OPERADOR.
     */
    public static Termino crearOperador(@NonNull String operador) {
        return new Termino(TipoTermino.OPERADOR, operador, 0, 0, true);
    }

    /**
     * Crea el signo de igualdad "=".
     *
     * @return Término de tipo IGUAL.
     */
    public static Termino crearIgual() {
        return new Termino(TipoTermino.IGUAL, "=", 0, 0, true);
    }

    /**
     * Crea una copia profunda del término con un nuevo {@link #id} único.
     * Útil cuando se necesita duplicar fichas en la UI sin aliasing.
     *
     * @return Nuevo término con los mismos datos pero distinto id.
     */
    public Termino copiar() {
        return new Termino(this.tipo, this.simbolo, this.coeficiente, this.valor, this.positivo);
    }

    // ════════════════════════════════════════════════════════════════════════
    //  Consultas semánticas de conveniencia
    // ════════════════════════════════════════════════════════════════════════

    /** {@code true} si el término es una variable (incógnita). */
    public boolean esVariable()  { return tipo == TipoTermino.VARIABLE; }

    /** {@code true} si el término es una constante numérica. */
    public boolean esConstante() { return tipo == TipoTermino.CONSTANTE; }

    /** {@code true} si el término es un operador aritmético. */
    public boolean esOperador()  { return tipo == TipoTermino.OPERADOR; }

    /** {@code true} si el término es el signo "=". */
    public boolean esIgual()     { return tipo == TipoTermino.IGUAL; }

    /**
     * Indica si este término puede cancelarse con {@code otro}.
     * Dos términos se cancelan (par cero) cuando son del mismo tipo,
     * tienen el mismo coeficiente/valor en valor absoluto y signos opuestos.
     *
     * @param otro Término candidato a cancelar.
     * @return {@code true} si forman un par cero.
     */
    public boolean cancelaCon(@NonNull Termino otro) {
        if (this.tipo != otro.tipo)         return false;
        if (this.positivo == otro.positivo) return false;      // mismo signo → no cancelan
        if (esVariable())  return Math.abs(this.coeficiente) == Math.abs(otro.coeficiente);
        if (esConstante()) return Math.abs(this.valor) == Math.abs(otro.valor);
        return false;
    }

    // ════════════════════════════════════════════════════════════════════════
    //  Getters
    // ════════════════════════════════════════════════════════════════════════

    @NonNull public String       getId()          { return id; }
    @NonNull public TipoTermino  getTipo()        { return tipo; }
    @NonNull public String       getSimbolo()     { return simbolo; }
                 public int      getCoeficiente() { return coeficiente; }
                 public int      getValor()       { return valor; }
                 public boolean  isPositivo()     { return positivo; }

    // ════════════════════════════════════════════════════════════════════════
    //  Setters (solo para manipulaciones algebraicas controladas)
    // ════════════════════════════════════════════════════════════════════════

    /**
     * Cambia el coeficiente de una variable y actualiza el símbolo.
     * Solo aplicable a términos de tipo {@link TipoTermino#VARIABLE}.
     *
     * @param nuevoCoef Nuevo coeficiente.
     * @throws IllegalStateException si el término no es VARIABLE.
     */
    public void setCoeficiente(int nuevoCoef) {
        if (tipo != TipoTermino.VARIABLE)
            throw new IllegalStateException("setCoeficiente solo aplica a VARIABLE");
        this.coeficiente = nuevoCoef;
        this.positivo    = nuevoCoef >= 0;
        if (nuevoCoef == 1)        this.simbolo = "x";
        else if (nuevoCoef == -1)  this.simbolo = "-x";
        else                       this.simbolo  = nuevoCoef + "x";
    }

    /**
     * Cambia el valor de una constante y actualiza el símbolo.
     * Solo aplicable a términos de tipo {@link TipoTermino#CONSTANTE}.
     *
     * @param nuevoValor Nuevo valor numérico.
     * @throws IllegalStateException si el término no es CONSTANTE.
     */
    public void setValor(int nuevoValor) {
        if (tipo != TipoTermino.CONSTANTE)
            throw new IllegalStateException("setValor solo aplica a CONSTANTE");
        this.valor    = nuevoValor;
        this.positivo = nuevoValor >= 0;
        this.simbolo  = nuevoValor >= 0 ? "+" + nuevoValor : String.valueOf(nuevoValor);
    }

    // ════════════════════════════════════════════════════════════════════════
    //  Object overrides
    // ════════════════════════════════════════════════════════════════════════

    @NonNull
    @Override
    public String toString() {
        return "Termino{id=" + id.substring(0, 8) + "…, tipo=" + tipo + ", simbolo='" + simbolo + "'}";
    }
}

package mx.unam.fc.icat.funz.repository;

import mx.unam.fc.icat.funz.data.AppState;

/**
 * AppStateRepository centraliza el acceso al estado persistido del usuario.
 *
 * Mantiene a los ViewModel desacoplados del singleton AppState,
 * facilitando pruebas y futuras migraciones de almacenamiento.
 */
public class AppStateRepository {

    private final AppState state;

    public AppStateRepository(AppState state) {
        this.state = state;
    }

    // Usuario / configuración
    public String getUsername() { return state.getUsername(); }
    public void setUsername(String username) { state.setUsername(username); }
    public boolean isDarkTheme() { return state.isDarkTheme(); }
    public void setDarkTheme(boolean darkTheme) { state.setDarkTheme(darkTheme); }

    // Progreso general
    public int getTotalPoints() { return state.getTotalPoints(); }
    public int getStreakDays() { return state.getStreakDays(); }
    public int getActiveModuleId() { return state.getActiveModuleId(); }
    public void setActiveModuleId(int moduleId) { state.setActiveModuleId(moduleId); }

    public int getCurrentStep(int moduleId) { return state.getCurrentStep(moduleId); }
    public int getModuleProgress(int moduleId) { return state.getModuleProgress(moduleId); }
    public int getModuleExerciseCount(int moduleId) { return state.getModuleExerciseCount(moduleId); }
    public boolean isStepDone(int moduleId, int step) { return state.isStepDone(moduleId, step); }
    public boolean isModuleComplete(int moduleId) { return state.isModuleComplete(moduleId); }
    public String getResumeBadge() { return state.getResumeBadge(); }

    // Sesión de ejercicios
    public void resetSession() { state.resetSession(); }
    public void markExerciseDone(int moduleId, int step, int totalSteps,
                                 boolean correct, boolean hintUsed, int points) {
        state.markExerciseDone(moduleId, step, totalSteps, correct, hintUsed, points);
    }
}

package mx.unam.fc.icat.funz.repository;

import android.content.Context;
import androidx.lifecycle.LiveData;

import java.util.List;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

import mx.unam.fc.icat.funz.db.DbSeeder;
import mx.unam.fc.icat.funz.db.Exercise;
import mx.unam.fc.icat.funz.db.ExerciseDao;
import mx.unam.fc.icat.funz.db.FunZDatabase;
import mx.unam.fc.icat.funz.db.Module;
import mx.unam.fc.icat.funz.db.ModuleDao;

/**
 * ExerciseRepository — única fuente de verdad para módulos y ejercicios.
 * <p>
 * Abstrae el acceso a Room y garantiza que las queries síncronas
 * no ocurran en el hilo principal.
 * <p>
 * El ViewModel crea una instancia de este repositorio; nunca accede
 * directamente a los DAOS.
 */
public class ExerciseRepository {

    private final ExerciseDao      exerciseDao;
    private final ModuleDao        moduleDao;
    private final ExecutorService  io = Executors.newSingleThreadExecutor();

    public ExerciseRepository(Context context) {
        FunZDatabase db = FunZDatabase.getInstance(context);
        exerciseDao = db.exerciseDao();
        moduleDao   = db.moduleDao();

        // Sembrar datos si la DB está vacía (idempotente)
        io.execute(() -> DbSeeder.seed(moduleDao, exerciseDao));
    }

    // ── Módulos ───────────────────────────────────────────────────────────────

    /** LiveData con todos los módulos en orden. La UI observa esto directamente. */
    public LiveData<List<Module>> getAllModules() {
        return moduleDao.getAllModules();
    }

    /**
     * Desbloquea el módulo con el ID dado (p.ej. al completar el anterior).
     * Se ejecuta en el hilo de IO.
     */
    public void unlockModule(int moduleId) {
        io.execute(() -> moduleDao.unlock(moduleId));
    }

    // ── Ejercicios ────────────────────────────────────────────────────────────

    /**
     * Carga un ejercicio específico de forma asíncrona y entrega el resultado
     * al callback en el hilo de IO. El ViewModel lo publica con postValue().
     *
     * @param moduleId  ID del módulo
     * @param stepOrder Número de paso (1-based)
     * @param callback  Recibe el Exercise (o null si no existe)
     */
    public void loadExercise(int moduleId, int stepOrder, Callback<Exercise> callback) {
        io.execute(() -> {
            Exercise ex = exerciseDao.getExerciseSync(moduleId, stepOrder);
            callback.onResult(ex);
        });
    }

    /** Total de ejercicios en un módulo (asíncrono, resultado vía callback). */
    public void countExercises(int moduleId, Callback<Integer> callback) {
        io.execute(() -> callback.onResult(exerciseDao.countByModule(moduleId)));
    }

    // ── Interfaz callback ─────────────────────────────────────────────────────

    public interface Callback<T> {
        void onResult(T result);
    }
}

package mx.unam.fc.icat.funz.repository;

import android.content.Context;
import androidx.lifecycle.LiveData;

import java.util.List;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

import mx.unam.fc.icat.funz.db.DbSeeder;
import mx.unam.fc.icat.funz.db.Exercise;
import mx.unam.fc.icat.funz.db.ExerciseDao;
import mx.unam.fc.icat.funz.db.FunZDatabase;
import mx.unam.fc.icat.funz.db.Module;
import mx.unam.fc.icat.funz.db.ModuleDao;

/**
 * ExerciseRepository — única fuente de verdad para módulos y ejercicios.
 * <p>
 * Abstrae el acceso a Room y garantiza que las queries síncronas
 * no ocurran en el hilo principal.
 * <p>
 * Se instancia una sola vez desde Application y los ViewModel lo reutilizan;
 * nunca acceden directamente a los DAO.
 */
public class ExerciseRepository {

    private final ExerciseDao exerciseDao;
    private final ModuleDao moduleDao;
    private final ExecutorService io;

    public ExerciseRepository(Context context, ExecutorService ioExecutor) {
        FunZDatabase db = FunZDatabase.getInstance(context);
        exerciseDao = db.exerciseDao();
        moduleDao = db.moduleDao();
        io = ioExecutor;

        // Sembrar datos si la DB está vacía (idempotente)
        io.execute(() -> DbSeeder.seed(moduleDao, exerciseDao));
    }

    /** Constructor de compatibilidad para usos aislados. */
    public ExerciseRepository(Context context) {
        this(context, Executors.newSingleThreadExecutor());
    }

    // ── Módulos ───────────────────────────────────────────────────────────────

    /** LiveData con todos los módulos en orden. La UI observa esto directamente. */
    public LiveData<List<Module>> getAllModules() {
        return moduleDao.getAllModules();
    }

    /**
     * Desbloquea el módulo con el ID dado (p.ej. al completar el anterior).
     * Se ejecuta en el hilo de IO.
     */
    public void unlockModule(int moduleId) {
        io.execute(() -> moduleDao.unlock(moduleId));
    }

    // ── Ejercicios ────────────────────────────────────────────────────────────

    /**
     * Carga un ejercicio específico de forma asíncrona y entrega el resultado
     * al callback en el hilo de IO. El ViewModel lo publica con postValue().
     *
     * @param moduleId  ID del módulo
     * @param stepOrder Número de paso (1-based)
     * @param callback  Recibe el Exercise (o null si no existe)
     */
    public void loadExercise(int moduleId, int stepOrder, Callback<Exercise> callback) {
        io.execute(() -> {
            Exercise ex = exerciseDao.getExerciseSync(moduleId, stepOrder);
            callback.onResult(ex);
        });
    }

    /** Total de ejercicios en un módulo (asíncrono, resultado vía callback). */
    public void countExercises(int moduleId, Callback<Integer> callback) {
        io.execute(() -> callback.onResult(exerciseDao.countByModule(moduleId)));
    }

    // ── Interfaz callback ─────────────────────────────────────────────────────

    public interface Callback<T> {
        void onResult(T result);
    }

    /**
     * Cierre explícito de recursos para casos donde el repositorio sea efímero.
     * No usar si el executor es compartido por toda la app.
     */
    public void shutdown() {
        io.shutdownNow();
    }
}

package mx.unam.fc.icat.funz.ui.ejercicios;

import android.content.ClipData;
import android.content.Intent;
import android.graphics.Color;
import android.os.Bundle;
import android.view.*;
import android.widget.*;
import androidx.appcompat.app.AlertDialog;
import androidx.appcompat.app.AppCompatActivity;
import androidx.lifecycle.ViewModelProvider;
import com.google.android.material.bottomsheet.BottomSheetDialog;
import com.google.android.material.chip.Chip;

import java.util.List;

import mx.unam.fc.icat.funz.db.Exercise;
import mx.unam.fc.icat.funz.viewmodel.ExerciseViewModel;
import mx.unam.fc.icat.funz.data.AppState;
import mx.unam.fc.icat.funz.ui.main.MainActivity;
import mx.unam.fc.icat.funz.ui.config.ConfiguracionActivity;
import mx.unam.fc.icat.funz.ui.sala.SalasActivity;
import mx.unam.fc.icat.funz.ui.temas.TemasActivity;
import mx.unam.fc.icat.funz.ui.temas.InfoEjemplosActivity;
import mx.unam.fc.icat.funz.ui.stats.EstadisticasActivity;
import mx.unam.fc.icat.funz.R;

/**
 * ExerciseActivity — Activity genérica para cualquier tipo de ejercicio.
 *
 * ╔══════════════════════════════════════════════════════════════════╗
 * ║  PARA AGREGAR UN NUEVO TIPO DE EJERCICIO                        ║
 * ║  1. Crear view_exercise_TIPO.xml con los controles necesarios   ║
 * ║  2. Inflar el nuevo layout en showPanelForType()                ║
 * ║  3. Conectar sus vistas en bindTypePanel()                      ║
 * ║  4. Agregar filas en SQLite (ExerciseType = "TIPO")             ║
 * ║  NO se toca ningún otro archivo.                                ║
 * ╚══════════════════════════════════════════════════════════════════╝
 *
 * Extras del Intent:
 *   "module_id"  (int) — ID del módulo
 *   "step_order" (int) — número de ejercicio dentro del módulo
 */
public class ExerciseActivity extends AppCompatActivity {

    // ── ViewModel ─────────────────────────────────────────────────────────────
    private ExerciseViewModel vm;

    // ── Vistas comunes (todas las pantallas) ──────────────────────────────────
    private Chip         chipTimer;
    private EditText     etAnswer;
    private LinearLayout drawerMenu;
    private FrameLayout  panelContainer;
    private View         loadingView;

    // ── Vistas del panel activo (se asignan al inflar) ─────────────────────────
    private View         currentPanel;

    // ── Extras del Intent ─────────────────────────────────────────────────────
    private int moduleId;
    private int stepOrder;

    // ════════════════════════════════════════════════════════════════════════
    //  onCreate
    // ════════════════════════════════════════════════════════════════════════

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        AppState state = AppState.getInstance();
        if (state.isDarkTheme()) setTheme(R.style.Theme_FunZ_Dark);
        setContentView(R.layout.activity_exercise);

        // Leer extras del Intent
        moduleId  = getIntent().getIntExtra("module_id",  1);
        stepOrder = getIntent().getIntExtra("step_order", 1);

        vm = new ViewModelProvider(this).get(ExerciseViewModel.class);

        bindCommonViews();
        observeViewModel();
        setupHamburger();

        // Cargar ejercicio de la DB (idempotente tras rotación)
        vm.loadExercise(moduleId, stepOrder);
    }

    // ════════════════════════════════════════════════════════════════════════
    //  Binding de vistas comunes
    // ════════════════════════════════════════════════════════════════════════

    private void bindCommonViews() {
        chipTimer      = findViewById(R.id.tv_timer);
        etAnswer       = findViewById(R.id.et_answer);
        panelContainer = findViewById(R.id.panel_container);
        loadingView    = findViewById(R.id.loading_view);
        drawerMenu     = findViewById(R.id.drawer_menu);
        drawerMenu.setVisibility(View.GONE);

        findViewById(R.id.btn_back).setOnClickListener(v -> { vm.cancelTimer(); finish(); });
        findViewById(R.id.btn_hint).setOnClickListener(v -> showHint());
        findViewById(R.id.btn_verify).setOnClickListener(v ->
                vm.verify(etAnswer.getText().toString()));
    }

    // ════════════════════════════════════════════════════════════════════════
    //  Observadores del ViewModel
    // ════════════════════════════════════════════════════════════════════════

    private void observeViewModel() {
        // Loading spinner
        vm.loading.observe(this, loading ->
                loadingView.setVisibility(Boolean.TRUE.equals(loading) ? View.VISIBLE : View.GONE));

        // Ejercicio cargado → inflar el panel correcto
        vm.exercise.observe(this, exercise -> {
            if (exercise == null) return;
            updateToolbarTitle(exercise);
            showPanelForType(exercise);
        });

        // Estado común
        vm.timerDisplay.observe(this, chipTimer::setText);
        vm.timerUrgent.observe(this, urgent -> {
            if (Boolean.TRUE.equals(urgent)) {
                chipTimer.setChipBackgroundColorResource(R.color.error_bg);
                chipTimer.setTextColor(getColor(R.color.error));
            }
        });
        vm.autoAnswer.observe(this, answer -> {
            if (answer != null && !answer.isEmpty()) etAnswer.setText(answer);
        });
        vm.timerFinished.observe(this, unused -> showTimeUpDialog());
        vm.exerciseResult.observe(this, this::handleResult);
    }

    // ════════════════════════════════════════════════════════════════════════
    //  Panel dinámico — el corazón de la arquitectura genérica
    // ════════════════════════════════════════════════════════════════════════

    /**
     * Infla el layout correcto según {@link Exercise#type} y conecta sus vistas.
     * Para agregar un nuevo tipo: añadir un case aquí y crear el XML.
     */
    private void showPanelForType(Exercise exercise) {
        panelContainer.removeAllViews();

        int layoutRes;
        switch (exercise.type) {
            case Exercise.TYPE_BALANZA: layoutRes = R.layout.view_exercise_balanza; break;
            case Exercise.TYPE_CLASICO: layoutRes = R.layout.view_exercise_clasico; break;
            case Exercise.TYPE_TILES:   layoutRes = R.layout.view_exercise_tiles;   break;
            default:
                Toast.makeText(this, "Tipo de ejercicio desconocido: " + exercise.type,
                        Toast.LENGTH_LONG).show();
                return;
        }

        currentPanel = getLayoutInflater().inflate(layoutRes, panelContainer, false);
        panelContainer.addView(currentPanel);
        bindTypePanel(exercise);
    }

    /**
     * Conecta las vistas específicas del tipo con los LiveData del ViewModel.
     */
    private void bindTypePanel(Exercise exercise) {
        switch (exercise.type) {
            case Exercise.TYPE_BALANZA: bindBalanzaPanel(exercise); break;
            case Exercise.TYPE_CLASICO: bindClasicoPanel(exercise); break;
            case Exercise.TYPE_TILES:   bindTilesPanel(exercise);   break;
        }
    }

    // ── Panel BALANZA ─────────────────────────────────────────────────────────

    private void bindBalanzaPanel(Exercise exercise) {
        TextView  tvLhs     = currentPanel.findViewById(R.id.tv_lhs);
        TextView  tvRhs     = currentPanel.findViewById(R.id.tv_rhs);
        TextView  tvStatus  = currentPanel.findViewById(R.id.tv_balance_status);
        ImageView ivBalanza = currentPanel.findViewById(R.id.iv_balanza);
        LinearLayout llOps  = currentPanel.findViewById(R.id.ll_op_buttons);

        vm.lhsExpr.observe(this, tvLhs::setText);
        vm.rhsExpr.observe(this, tvRhs::setText);
        vm.statusMessage.observe(this, tvStatus::setText);
        vm.statusPositive.observe(this, pos -> {
            if (pos == null) tvStatus.setTextColor(getColor(android.R.color.darker_gray));
            else tvStatus.setTextColor(getColor(pos ? R.color.accent_green : R.color.warn_chip_text));
        });
        vm.balanced.observe(this, balanced ->
                ivBalanza.setColorFilter(getColor(Boolean.TRUE.equals(balanced)
                        ? R.color.accent_green : R.color.color_primary)));

        // Botones de operación generados dinámicamente desde la DB
        vm.ops.observe(this, opList -> {
            llOps.removeAllViews();
            for (String op : opList) {
                Button btn = new Button(this, null, com.google.android.material.R.style.Widget_Material3_Button_OutlinedButton);
                btn.setText(op);
                LinearLayout.LayoutParams lp = new LinearLayout.LayoutParams(0,
                        LinearLayout.LayoutParams.WRAP_CONTENT, 1f);
                lp.setMargins(4, 0, 4, 0);
                btn.setLayoutParams(lp);
                btn.setOnClickListener(v -> vm.applyOp(op));
                llOps.addView(btn);
            }
        });
    }

    // ── Panel CLÁSICO ─────────────────────────────────────────────────────────

    private void bindClasicoPanel(Exercise exercise) {
        TextView tvEquation = currentPanel.findViewById(R.id.tv_equation_display);
        LinearLayout llSteps = currentPanel.findViewById(R.id.ll_solution_steps);

        tvEquation.setText(exercise.equation);

        // Renderizar pasos desde JSON
        List<String> steps = ExerciseViewModel.parseJson(exercise.solutionSteps);
        llSteps.removeAllViews();
        for (int i = 0; i < steps.size(); i++) {
            TextView tv = new TextView(this);
            tv.setText(steps.get(i));
            tv.setTextColor(getColor(steps.get(i).startsWith("  ")
                    ? R.color.color_primary : R.color.text_primary));
            tv.setTextSize(14f);
            tv.setPadding(0, 4, 0, 4);
            llSteps.addView(tv);
        }
    }

    // ── Panel TILES ───────────────────────────────────────────────────────────

    private void bindTilesPanel(Exercise exercise) {
        LinearLayout llLeft  = currentPanel.findViewById(R.id.ll_tiles_left);
        LinearLayout llRight = currentPanel.findViewById(R.id.ll_tiles_right);
        TextView     tvSt    = currentPanel.findViewById(R.id.tv_tiles_status);

        vm.statusMessage.observe(this, tvSt::setText);
        vm.statusPositive.observe(this, pos ->
                tvSt.setTextColor(getColor(Boolean.TRUE.equals(pos)
                        ? R.color.accent_green : R.color.warn_chip_text)));

        vm.leftTilesLd.observe(this, tiles -> {
            renderTiles(tiles, llLeft, "L");
            setupDropTarget(llLeft, "L");
        });
        vm.rightTilesLd.observe(this, tiles -> {
            renderTiles(tiles, llRight, "R");
            setupDropTarget(llRight, "R");
        });
    }

    private void renderTiles(List<String> tiles, LinearLayout container, String side) {
        container.removeAllViews();
        for (int i = 0; i < tiles.size(); i++) {
            container.addView(makeTileView(tiles.get(i), i, side));
        }
    }

    private View makeTileView(String label, int idx, String side) {
        TextView tv = new TextView(this);
        tv.setText(label);
        tv.setTextColor(Color.WHITE);
        tv.setTextSize(10f);
        tv.setGravity(Gravity.CENTER);

        boolean isX = label.equals("x") || label.contains("/");
        int bgColor = isX ? getColor(R.color.color_primary)
                : (label.startsWith("-") ? 0xFFEF4444 : 0xFF3B82F6);
        tv.setBackgroundColor(bgColor);

        int w = isX ? dpToPx(44) : dpToPx(22);
        LinearLayout.LayoutParams lp = new LinearLayout.LayoutParams(w, dpToPx(22));
        lp.setMargins(dpToPx(3), dpToPx(3), dpToPx(3), dpToPx(3));
        tv.setLayoutParams(lp);
        tv.setPadding(dpToPx(4), dpToPx(2), dpToPx(4), dpToPx(2));

        tv.setOnLongClickListener(v -> {
            ClipData cd = ClipData.newPlainText("tile", side + "_" + idx + "_" + label);
            v.startDragAndDrop(cd, new View.DragShadowBuilder(v), v, 0);
            return true;
        });
        if (!isX) {
            tv.setOnClickListener(v -> vm.moveTile(side, idx, label));
        }
        return tv;
    }

    private void setupDropTarget(LinearLayout container, String targetSide) {
        container.setOnDragListener((v, event) -> {
            if (event.getAction() == DragEvent.ACTION_DROP) {
                String[] p = event.getClipData().getItemAt(0).getText().toString().split("_");
                if (p.length == 3 && !p[0].equals(targetSide) && !p[2].equals("x"))
                    vm.moveTile(p[0], Integer.parseInt(p[1]), p[2]);
            }
            return true;
        });
    }

    private int dpToPx(int dp) {
        return (int)(dp * getResources().getDisplayMetrics().density);
    }

    // ════════════════════════════════════════════════════════════════════════
    //  Pista (BottomSheet)
    // ════════════════════════════════════════════════════════════════════════

    private void showHint() {
        Exercise ex = vm.exercise.getValue();
        if (ex == null) return;
        vm.useHint();

        BottomSheetDialog sheet = new BottomSheetDialog(this);
        View v = getLayoutInflater().inflate(R.layout.bottom_sheet_hint, null);
        ((TextView) v.findViewById(R.id.tv_hint_content)).setText(ex.hintText);
        v.findViewById(R.id.btn_close_hint).setOnClickListener(b -> sheet.dismiss());
        sheet.setContentView(v);
        sheet.show();
    }

    // ════════════════════════════════════════════════════════════════════════
    //  Resultado del ejercicio
    // ════════════════════════════════════════════════════════════════════════

    private void handleResult(ExerciseViewModel.ExerciseResult result) {
        switch (result) {
            case EMPTY_INPUT:
                Toast.makeText(this, "Ingresa tu respuesta", Toast.LENGTH_SHORT).show();
                break;
            case CORRECT:
                showResultDialog(true, false);
                break;
            case CORRECT_WITH_HINT:
                showResultDialog(true, true);
                break;
            case INCORRECT:
                showResultDialog(false, false);
                break;
        }
    }

    private void showResultDialog(boolean correct, boolean withHint) {
        Exercise ex = vm.exercise.getValue();
        AlertDialog.Builder b = new AlertDialog.Builder(this);
        if (correct) {
            int pts = ex != null ? (withHint ? ex.pointsHint : ex.pointsCorrect) : (withHint ? 50 : 100);
            String msg = "¡Bien hecho!\n+" + pts + " puntos";
            if (withHint) msg += "\n\nUsaste pista. ¡Intenta sin pista para +" + pts + " extra!";
            b.setTitle(" ¡Correcto!")
                    .setMessage(msg)
                    .setPositiveButton(isLastStep() ? "Ver resultados" : "Siguiente →",
                            (d, w) -> goToNext())
                    .setCancelable(false);
            if (withHint) b.setNeutralButton("Sin pista", (d, w) -> {
                etAnswer.setText("");
                vm.retryWithoutHint();
            });
        } else {
            b.setTitle(" Incorrecto")
                    .setMessage("Revisa la sección de Información para reforzar el tema.")
                    .setPositiveButton(" Info", (d, w) -> goToInfo())
                    .setNegativeButton("Reintentar", (d, w) -> { etAnswer.setText(""); vm.retryCurrentExercise(); })
                    .setNeutralButton("Salir", (d, w) -> finish())
                    .setCancelable(false);
        }
        b.show();
    }

    private void showTimeUpDialog() {
        new AlertDialog.Builder(this)
                .setTitle("⏰ ¡Tiempo agotado!")
                .setPositiveButton("Reintentar", (d, w) -> { etAnswer.setText(""); vm.retryCurrentExercise(); })
                .setNegativeButton("Salir", (d, w) -> finish())
                .setCancelable(false).show();
    }

    // ════════════════════════════════════════════════════════════════════════
    //  Navegación
    // ════════════════════════════════════════════════════════════════════════

    private boolean isLastStep() {
        AppState state = AppState.getInstance();
        return stepOrder >= state.getModuleExerciseCount(moduleId);
    }

    private void goToNext() {
        AppState state = AppState.getInstance();
        if (isLastStep()) {
            startActivity(new Intent(this, FinEjerciciosActivity.class));
        } else {
            Intent i = new Intent(this, ExerciseActivity.class);
            i.putExtra("module_id",  moduleId);
            i.putExtra("step_order", stepOrder + 1);
            startActivity(i);
        }
        finish();
    }

    private void goToInfo() {
        Intent i = new Intent(this, InfoEjemplosActivity.class);
        i.putExtra("module_id", moduleId);
        i.putExtra("tab", 0);
        startActivity(i);
        finish();
    }

    private void updateToolbarTitle(Exercise exercise) {
        TextView tvTitle = findViewById(R.id.tv_toolbar_title);
        if (tvTitle != null) {
            tvTitle.setText("Módulo " + moduleId + " · Ej. " + stepOrder);
        }
    }

    // ════════════════════════════════════════════════════════════════════════
    //  Menú hamburguesa
    // ════════════════════════════════════════════════════════════════════════

    private void setupHamburger() {
        findViewById(R.id.btn_hamburger).setOnClickListener(v ->
                drawerMenu.setVisibility(
                        drawerMenu.getVisibility() == View.VISIBLE ? View.GONE : View.VISIBLE));
        setupDrawerItem(R.id.drawer_inicio, MainActivity.class);
        setupDrawerItem(R.id.drawer_temas,  TemasActivity.class);
        setupDrawerItem(R.id.drawer_salas,  SalasActivity.class);
        setupDrawerItem(R.id.drawer_stats,  EstadisticasActivity.class);
        setupDrawerItem(R.id.drawer_config, ConfiguracionActivity.class);
    }

    private void setupDrawerItem(int viewId, Class<?> target) {
        View item = findViewById(viewId);
        if (item != null) item.setOnClickListener(v -> {
            vm.cancelTimer();
            drawerMenu.setVisibility(View.GONE);
            startActivity(new Intent(this, target));
        });
    }

    @Override protected void onDestroy() { super.onDestroy(); vm.cancelTimer(); }
}

package mx.unam.fc.icat.funz.ui.ejercicios;

import android.content.ClipData;
import android.content.Intent;
import android.graphics.Color;
import android.os.Bundle;
import android.util.TypedValue;
import android.view.*;
import android.widget.*;
import androidx.appcompat.app.AppCompatActivity;
import androidx.lifecycle.ViewModelProvider;
import com.google.android.material.dialog.MaterialAlertDialogBuilder;
import com.google.android.material.bottomsheet.BottomSheetDialog;
import com.google.android.material.chip.Chip;

import java.util.List;

import mx.unam.fc.icat.funz.db.Exercise;
import mx.unam.fc.icat.funz.viewmodel.ExerciseViewModel;
import mx.unam.fc.icat.funz.data.AppState;
import mx.unam.fc.icat.funz.ui.main.MainActivity;
import mx.unam.fc.icat.funz.ui.config.ConfiguracionActivity;
import mx.unam.fc.icat.funz.ui.sala.SalasActivity;
import mx.unam.fc.icat.funz.ui.temas.TemasActivity;
import mx.unam.fc.icat.funz.ui.temas.InfoEjemplosActivity;
import mx.unam.fc.icat.funz.ui.stats.EstadisticasActivity;
import mx.unam.fc.icat.funz.R;

/**
 * ExerciseActivity — Activity genérica para cualquier tipo de ejercicio.
 *
 * ╔══════════════════════════════════════════════════════════════════╗
 * ║  PARA AGREGAR UN NUEVO TIPO DE EJERCICIO                        ║
 * ║  1. Crear view_exercise_TIPO.xml con los controles necesarios   ║
 * ║  2. Inflar el nuevo layout en showPanelForType()                ║
 * ║  3. Conectar sus vistas en bindTypePanel()                      ║
 * ║  4. Agregar filas en SQLite (ExerciseType = "TIPO")             ║
 * ║  NO se toca ningún otro archivo.                                ║
 * ╚══════════════════════════════════════════════════════════════════╝
 *
 * Extras del Intent:
 *   "module_id"  (int) — ID del módulo
 *   "step_order" (int) — número de ejercicio dentro del módulo
 */
public class ExerciseActivity extends AppCompatActivity {

    // ── ViewModel ─────────────────────────────────────────────────────────────
    private ExerciseViewModel vm;

    // ── Vistas comunes (todas las pantallas) ──────────────────────────────────
    private Chip         chipTimer;
    private EditText     etAnswer;
    private LinearLayout drawerMenu;
    private FrameLayout  panelContainer;
    private View         loadingView;

    // ── Vistas del panel activo (se asignan al inflar) ─────────────────────────
    private View         currentPanel;

    // ── Extras del Intent ─────────────────────────────────────────────────────
    private int moduleId;
    private int stepOrder;

    // ════════════════════════════════════════════════════════════════════════
    //  onCreate
    // ════════════════════════════════════════════════════════════════════════

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        AppState state = AppState.getInstance();
        if (state.isDarkTheme()) setTheme(R.style.Theme_FunZ_Dark);
        setContentView(R.layout.activity_exercise);

        // Leer extras del Intent
        moduleId  = getIntent().getIntExtra("module_id",  1);
        stepOrder = getIntent().getIntExtra("step_order", 1);

        vm = new ViewModelProvider(this).get(ExerciseViewModel.class);

        bindCommonViews();
        observeViewModel();
        setupHamburger();

        // Cargar ejercicio de la DB (idempotente tras rotación)
        vm.loadExercise(moduleId, stepOrder);
    }

    // ════════════════════════════════════════════════════════════════════════
    //  Binding de vistas comunes
    // ════════════════════════════════════════════════════════════════════════

    private void bindCommonViews() {
        chipTimer      = findViewById(R.id.tv_timer);
        etAnswer       = findViewById(R.id.et_answer);
        panelContainer = findViewById(R.id.panel_container);
        loadingView    = findViewById(R.id.loading_view);
        drawerMenu     = findViewById(R.id.drawer_menu);
        drawerMenu.setVisibility(View.GONE);

        findViewById(R.id.btn_back).setOnClickListener(v -> { vm.cancelTimer(); finish(); });
        findViewById(R.id.btn_hint).setOnClickListener(v -> showHint());
        findViewById(R.id.btn_verify).setOnClickListener(v ->
                vm.verify(etAnswer.getText().toString()));
    }

    // ════════════════════════════════════════════════════════════════════════
    //  Observadores del ViewModel
    // ════════════════════════════════════════════════════════════════════════

    private void observeViewModel() {
        // Loading spinner
        vm.loading.observe(this, loading ->
                loadingView.setVisibility(Boolean.TRUE.equals(loading) ? View.VISIBLE : View.GONE));

        // Ejercicio cargado → inflar el panel correcto
        vm.exercise.observe(this, exercise -> {
            if (exercise == null) return;
            updateToolbarTitle(exercise);
            showPanelForType(exercise);
        });

        // Estado común
        vm.timerDisplay.observe(this, chipTimer::setText);
        vm.timerUrgent.observe(this, urgent -> {
            if (Boolean.TRUE.equals(urgent)) {
                chipTimer.setChipBackgroundColorResource(R.color.error_bg);
                chipTimer.setTextColor(getColor(R.color.error));
            }
        });
        vm.autoAnswer.observe(this, answer -> {
            if (answer != null && !answer.isEmpty()) etAnswer.setText(answer);
        });
        vm.timerFinished.observe(this, unused -> showTimeUpDialog());
        vm.exerciseResult.observe(this, this::handleResult);
    }

    // ════════════════════════════════════════════════════════════════════════
    //  Panel dinámico — el corazón de la arquitectura genérica
    // ════════════════════════════════════════════════════════════════════════

    /**
     * Infla el layout correcto según {@link Exercise#type} y conecta sus vistas.
     * Para agregar un nuevo tipo: añadir un case aquí y crear el XML.
     */
    private void showPanelForType(Exercise exercise) {
        panelContainer.removeAllViews();

        int layoutRes;
        switch (exercise.type) {
            case Exercise.TYPE_BALANZA: layoutRes = R.layout.view_exercise_balanza; break;
            case Exercise.TYPE_CLASICO: layoutRes = R.layout.view_exercise_clasico; break;
            case Exercise.TYPE_TILES:   layoutRes = R.layout.view_exercise_tiles;   break;
            default:
                Toast.makeText(this, "Tipo de ejercicio desconocido: " + exercise.type,
                        Toast.LENGTH_LONG).show();
                return;
        }

        currentPanel = getLayoutInflater().inflate(layoutRes, panelContainer, false);
        panelContainer.addView(currentPanel);
        bindTypePanel(exercise);
    }

    /**
     * Conecta las vistas específicas del tipo con los LiveData del ViewModel.
     */
    private void bindTypePanel(Exercise exercise) {
        switch (exercise.type) {
            case Exercise.TYPE_BALANZA: bindBalanzaPanel(exercise); break;
            case Exercise.TYPE_CLASICO: bindClasicoPanel(exercise); break;
            case Exercise.TYPE_TILES:   bindTilesPanel(exercise);   break;
        }
    }

    // ── Panel BALANZA ─────────────────────────────────────────────────────────

    private void bindBalanzaPanel(Exercise exercise) {
        TextView  tvLhs     = currentPanel.findViewById(R.id.tv_lhs);
        TextView  tvRhs     = currentPanel.findViewById(R.id.tv_rhs);
        TextView  tvStatus  = currentPanel.findViewById(R.id.tv_balance_status);
        ImageView ivBalanza = currentPanel.findViewById(R.id.iv_balanza);
        LinearLayout llOps  = currentPanel.findViewById(R.id.ll_op_buttons);

        vm.lhsExpr.observe(this, tvLhs::setText);
        vm.rhsExpr.observe(this, tvRhs::setText);
        vm.statusMessage.observe(this, tvStatus::setText);
        vm.statusPositive.observe(this, pos -> {
            if (pos == null) {
                tvStatus.setTextColor(resolveThemeColor(com.google.android.material.R.attr.colorOnSurfaceVariant));
            } else {
                tvStatus.setTextColor(pos
                        ? getColor(R.color.accent_green)
                        : resolveThemeColor(R.attr.colorWarnChipText));
            }
        });
        vm.balanced.observe(this, balanced ->
                ivBalanza.setColorFilter(Boolean.TRUE.equals(balanced)
                        ? getColor(R.color.accent_green)
                        : resolveThemeColor(androidx.appcompat.R.attr.colorPrimary)));

        // Botones de operación generados dinámicamente desde la DB
        vm.ops.observe(this, opList -> {
            llOps.removeAllViews();
            for (String op : opList) {
                Button btn = new Button(this, null, com.google.android.material.R.style.Widget_Material3_Button_OutlinedButton);
                btn.setText(op);
                LinearLayout.LayoutParams lp = new LinearLayout.LayoutParams(0,
                        LinearLayout.LayoutParams.WRAP_CONTENT, 1f);
                lp.setMargins(4, 0, 4, 0);
                btn.setLayoutParams(lp);
                btn.setOnClickListener(v -> vm.applyOp(op));
                llOps.addView(btn);
            }
        });
    }

    // ── Panel CLÁSICO ─────────────────────────────────────────────────────────

    private void bindClasicoPanel(Exercise exercise) {
        TextView tvEquation = currentPanel.findViewById(R.id.tv_equation_display);
        LinearLayout llSteps = currentPanel.findViewById(R.id.ll_solution_steps);

        tvEquation.setText(exercise.equation);

        // Renderizar pasos desde JSON
        List<String> steps = ExerciseViewModel.parseJson(exercise.solutionSteps);
        llSteps.removeAllViews();
        for (int i = 0; i < steps.size(); i++) {
            TextView tv = new TextView(this);
            tv.setText(steps.get(i));
            tv.setTextColor(steps.get(i).startsWith("  ")
                    ? resolveThemeColor(androidx.appcompat.R.attr.colorPrimary)
                    : resolveThemeColor(com.google.android.material.R.attr.colorOnSurface));
            tv.setTextSize(14f);
            tv.setPadding(0, 4, 0, 4);
            llSteps.addView(tv);
        }
    }

    // ── Panel TILES ───────────────────────────────────────────────────────────

    private void bindTilesPanel(Exercise exercise) {
        LinearLayout llLeft  = currentPanel.findViewById(R.id.ll_tiles_left);
        LinearLayout llRight = currentPanel.findViewById(R.id.ll_tiles_right);
        TextView     tvSt    = currentPanel.findViewById(R.id.tv_tiles_status);

        vm.statusMessage.observe(this, tvSt::setText);
        vm.statusPositive.observe(this, pos ->
                tvSt.setTextColor(Boolean.TRUE.equals(pos)
                        ? getColor(R.color.accent_green)
                        : resolveThemeColor(R.attr.colorWarnChipText)));

        vm.leftTilesLd.observe(this, tiles -> {
            renderTiles(tiles, llLeft, "L");
            setupDropTarget(llLeft, "L");
        });
        vm.rightTilesLd.observe(this, tiles -> {
            renderTiles(tiles, llRight, "R");
            setupDropTarget(llRight, "R");
        });
    }

    private void renderTiles(List<String> tiles, LinearLayout container, String side) {
        container.removeAllViews();
        for (int i = 0; i < tiles.size(); i++) {
            container.addView(makeTileView(tiles.get(i), i, side));
        }
    }

    private View makeTileView(String label, int idx, String side) {
        TextView tv = new TextView(this);
        tv.setText(label);
        tv.setTextColor(Color.WHITE);
        tv.setTextSize(10f);
        tv.setGravity(Gravity.CENTER);

        boolean isX = label.equals("x") || label.contains("/");
        int bgColor = isX ? getColor(R.color.color_primary)
                : (label.startsWith("-") ? 0xFFEF4444 : 0xFF3B82F6);
        tv.setBackgroundColor(bgColor);

        int w = isX ? dpToPx(44) : dpToPx(22);
        LinearLayout.LayoutParams lp = new LinearLayout.LayoutParams(w, dpToPx(22));
        lp.setMargins(dpToPx(3), dpToPx(3), dpToPx(3), dpToPx(3));
        tv.setLayoutParams(lp);
        tv.setPadding(dpToPx(4), dpToPx(2), dpToPx(4), dpToPx(2));

        tv.setOnLongClickListener(v -> {
            ClipData cd = ClipData.newPlainText("tile", side + "_" + idx + "_" + label);
            v.startDragAndDrop(cd, new View.DragShadowBuilder(v), v, 0);
            return true;
        });
        if (!isX) {
            tv.setOnClickListener(v -> vm.moveTile(side, idx, label));
        }
        return tv;
    }

    private void setupDropTarget(LinearLayout container, String targetSide) {
        container.setOnDragListener((v, event) -> {
            if (event.getAction() == DragEvent.ACTION_DROP) {
                String[] p = event.getClipData().getItemAt(0).getText().toString().split("_");
                if (p.length == 3 && !p[0].equals(targetSide) && !p[2].equals("x"))
                    vm.moveTile(p[0], Integer.parseInt(p[1]), p[2]);
            }
            return true;
        });
    }

    private int dpToPx(int dp) {
        return (int)(dp * getResources().getDisplayMetrics().density);
    }

    private int resolveThemeColor(int attrResId) {
        TypedValue tv = new TypedValue();
        getTheme().resolveAttribute(attrResId, tv, true);
        return tv.data;
    }

    // ════════════════════════════════════════════════════════════════════════
    //  Pista (BottomSheet)
    // ════════════════════════════════════════════════════════════════════════

    private void showHint() {
        Exercise ex = vm.exercise.getValue();
        if (ex == null) return;
        vm.useHint();

        BottomSheetDialog sheet = new BottomSheetDialog(this);
        View v = getLayoutInflater().inflate(R.layout.bottom_sheet_hint, null);
        ((TextView) v.findViewById(R.id.tv_hint_content)).setText(ex.hintText);
        v.findViewById(R.id.btn_close_hint).setOnClickListener(b -> sheet.dismiss());
        sheet.setContentView(v);
        sheet.show();
    }

    // ════════════════════════════════════════════════════════════════════════
    //  Resultado del ejercicio
    // ════════════════════════════════════════════════════════════════════════

    private void handleResult(ExerciseViewModel.ExerciseResult result) {
        switch (result) {
            case EMPTY_INPUT:
                Toast.makeText(this, "Ingresa tu respuesta", Toast.LENGTH_SHORT).show();
                break;
            case CORRECT:
                showResultDialog(true, false);
                break;
            case CORRECT_WITH_HINT:
                showResultDialog(true, true);
                break;
            case INCORRECT:
                showResultDialog(false, false);
                break;
        }
    }

    private void showResultDialog(boolean correct, boolean withHint) {
        Exercise ex = vm.exercise.getValue();
        MaterialAlertDialogBuilder b = new MaterialAlertDialogBuilder(this);
        if (correct) {
            int pts = ex != null ? (withHint ? ex.pointsHint : ex.pointsCorrect) : (withHint ? 50 : 100);
            String msg = "¡Bien hecho!\n+" + pts + " puntos";
            if (withHint) msg += "\n\nUsaste pista. ¡Intenta sin pista para +" + pts + " extra!";
            b.setTitle(" ¡Correcto!")
                    .setMessage(msg)
                    .setPositiveButton(isLastStep() ? "Ver resultados" : "Siguiente →",
                            (d, w) -> goToNext())
                    .setCancelable(false);
            if (withHint) b.setNeutralButton("Sin pista", (d, w) -> {
                etAnswer.setText("");
                vm.retryWithoutHint();
            });
        } else {
            b.setTitle(" Incorrecto")
                    .setMessage("Revisa la sección de Información para reforzar el tema.")
                    .setPositiveButton(" Info", (d, w) -> goToInfo())
                    .setNegativeButton("Reintentar", (d, w) -> { etAnswer.setText(""); vm.retryCurrentExercise(); })
                    .setNeutralButton("Salir", (d, w) -> finish())
                    .setCancelable(false);
        }
        b.show();
    }

    private void showTimeUpDialog() {
        new MaterialAlertDialogBuilder(this)
                .setTitle("⏰ ¡Tiempo agotado!")
                .setPositiveButton("Reintentar", (d, w) -> { etAnswer.setText(""); vm.retryCurrentExercise(); })
                .setNegativeButton("Salir", (d, w) -> finish())
                .setCancelable(false).show();
    }

    // ════════════════════════════════════════════════════════════════════════
    //  Navegación
    // ════════════════════════════════════════════════════════════════════════

    private boolean isLastStep() {
        AppState state = AppState.getInstance();
        return stepOrder >= state.getModuleExerciseCount(moduleId);
    }

    private void goToNext() {
        AppState state = AppState.getInstance();
        if (isLastStep()) {
            startActivity(new Intent(this, FinEjerciciosActivity.class));
        } else {
            Intent i = new Intent(this, ExerciseActivity.class);
            i.putExtra("module_id",  moduleId);
            i.putExtra("step_order", stepOrder + 1);
            startActivity(i);
        }
        finish();
    }

    private void goToInfo() {
        Intent i = new Intent(this, InfoEjemplosActivity.class);
        i.putExtra("module_id", moduleId);
        i.putExtra("tab", 0);
        startActivity(i);
        finish();
    }

    private void updateToolbarTitle(Exercise exercise) {
        TextView tvTitle = findViewById(R.id.tv_toolbar_title);
        if (tvTitle != null) {
            tvTitle.setText("Módulo " + moduleId + " · Ej. " + stepOrder);
        }
    }

    // ════════════════════════════════════════════════════════════════════════
    //  Menú hamburguesa
    // ════════════════════════════════════════════════════════════════════════

    private void setupHamburger() {
        findViewById(R.id.btn_hamburger).setOnClickListener(v ->
                drawerMenu.setVisibility(
                        drawerMenu.getVisibility() == View.VISIBLE ? View.GONE : View.VISIBLE));
        setupDrawerItem(R.id.drawer_inicio, MainActivity.class);
        setupDrawerItem(R.id.drawer_temas,  TemasActivity.class);
        setupDrawerItem(R.id.drawer_salas,  SalasActivity.class);
        setupDrawerItem(R.id.drawer_stats,  EstadisticasActivity.class);
        setupDrawerItem(R.id.drawer_config, ConfiguracionActivity.class);
    }

    private void setupDrawerItem(int viewId, Class<?> target) {
        View item = findViewById(viewId);
        if (item != null) item.setOnClickListener(v -> {
            vm.cancelTimer();
            drawerMenu.setVisibility(View.GONE);
            startActivity(new Intent(this, target));
        });
    }

    @Override protected void onDestroy() { super.onDestroy(); vm.cancelTimer(); }
}

package mx.unam.fc.icat.funz.viewmodel;

import androidx.lifecycle.LiveData;
import androidx.lifecycle.MutableLiveData;
import androidx.lifecycle.ViewModel;

import mx.unam.fc.icat.funz.data.AppState;
import mx.unam.fc.icat.funz.utils.SingleLiveEvent;

/**
 * ConfiguracionViewModel — ViewModel para la pantalla N (Configuración).
 *
 * Responsabilidades:
 *   - Exponer los valores actuales de username y darkTheme para pre-cargar
 *     los campos de la pantalla.
 *   - Procesar y validar el guardado de la configuración.
 *   - Emitir un evento de un solo disparo que indica si la Activity
 *     debe recrearse (porque el tema cambió) o solo mostrar un Toast.
 */
public class ConfiguracionViewModel extends ViewModel {

    private final AppState state = AppState.getInstance();

    // ── LiveData de valores actuales (para pre-cargar la UI) ──────────────────

    private final MutableLiveData<String>  _currentUsername  = new MutableLiveData<>();
    public  final LiveData<String>          currentUsername   = _currentUsername;

    private final MutableLiveData<Boolean> _currentDarkTheme = new MutableLiveData<>();
    public  final LiveData<Boolean>         currentDarkTheme  = _currentDarkTheme;

    // ── Eventos de un solo disparo ────────────────────────────────────────────

    /**
     * Emite el resultado del guardado.
     * SaveResult.THEME_CHANGED → la Activity debe llamar a recreate().
     * SaveResult.SAVED         → solo mostrar Toast de confirmación.
     */
    private final SingleLiveEvent<SaveResult> _saveEvent = new SingleLiveEvent<>();
    public  final LiveData<SaveResult>         saveEvent  = _saveEvent;

    // ════════════════════════════════════════════════════════════════════════
    //  Carga inicial
    // ════════════════════════════════════════════════════════════════════════

    /** Carga los valores actuales de AppState para pre-llenar la pantalla. */
    public void loadCurrentConfig() {
        _currentUsername.setValue(state.getUsername());
        _currentDarkTheme.setValue(state.isDarkTheme());
    }

    // ════════════════════════════════════════════════════════════════════════
    //  Guardado de configuración
    // ════════════════════════════════════════════════════════════════════════

    /**
     * Persiste los cambios de configuración en AppState y emite el evento
     * apropiado para que la Activity reaccione.
     *
     * @param newUsername Nombre introducido por el usuario (puede estar vacío)
     * @param newDark     true si el usuario seleccionó tema oscuro
     */
    public void saveConfig(String newUsername, boolean newDark) {
        // Actualizar nombre solo si no está vacío
        if (newUsername != null && !newUsername.trim().isEmpty()) {
            state.setUsername(newUsername.trim());
        }

        boolean themeChanged = newDark != state.isDarkTheme();
        state.setDarkTheme(newDark);

        _saveEvent.setValue(themeChanged ? SaveResult.THEME_CHANGED : SaveResult.SAVED);
    }

    // ════════════════════════════════════════════════════════════════════════
    //  Enum de resultado del guardado
    // ════════════════════════════════════════════════════════════════════════

    public enum SaveResult {
        /** Se guardó correctamente y no hay cambio de tema; solo mostrar Toast. */
        SAVED,
        /** El tema cambió; la Activity debe llamar a recreate(). */
        THEME_CHANGED
    }
}

